var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"ARC-EA2, 구 아스완","JPN":"ARC-EA2、旧アスワン","ENG":"ARC-EA2, former Aswan","TWN":"ARC-EA2，舊阿斯旺","DEU":"ARC-EA2, former Aswan","FRA":"ARC-EA2, former Aswan"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 3.3","JPN":"CSE Lv.3.3","ENG":"CSE Lv. 3.3","TWN":"CSE Lv. 3.3","DEU":"CSE Lv. 3.3","FRA":"CSE Lv. 3.3"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"지나치게 조용해.","JPN":"静かすぎますね。","ENG":"It's too quiet.","TWN":"安靜過頭了。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"분명 항구 쪽에서 상대한 숫자를 보면 이렇게 조용할 리가 없을 텐데.","JPN":"港で相手した数を考えると、ここがこんなに静かなはずがないのですが。","ENG":"Judging by how many we fought at the harbor, there's no way it should be this quiet.","TWN":"依據我們在港口遇到的數量，這裡不可能這麼安靜。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"으으… 꼭 유령이라도 튀어나올 것 같아.","JPN":"うう……幽霊でも出てきそう。","ENG":"Ugh... Feels like a ghost could pop out any second.","TWN":"呃……感覺好像隨時會有幽靈出現。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그럼 내가 앞장서도록 하지, 소녀여.","JPN":"では私が先頭に立つとしよう、少女よ。","ENG":"Then allow me to lead the way, girl.","TWN":"那就讓我走在前面吧，少女。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"약자를 보호하고, 악한 것을 물리치는 것이 파사의 심판자가 걸어야 하는 길.","JPN":"弱者を保護し、邪悪なものを打ち倒す。それが破邪の審判者の歩むべき道。","ENG":"To protect the weak and strike down evil is the path of the Judicator of Evil.","TWN":"保護弱者、打倒邪惡，乃是踏上破邪審判者之路者的使命。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"유령 따위에 벌벌 떠는 그대와는 달리, 나는 그런 것에 연연하지 않거든.","JPN":"幽霊などに怯える君とは違い、私はそんなもの気に留めないのでな。","ENG":"Unlike you, who tremble at ghosts, such trifles don't concern me.","TWN":"跟因為區區幽靈就嚇到發抖的你不一樣，我可不會被影響。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"뭐, 뭐어?! 너 지금 이 상황에서까지 그러는 거야?","JPN":"あ、あなた！　こんな時にまでそういう態度とるの？","ENG":"W-what?! You are doing this even now?","TWN":"什、什麼？！你在這種時候還要這樣？！"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"하! 정의의 사자 지망생이 그까짓 유령에 겁먹을 것 같아?","JPN":"ふん！　正義の味方の志願者たる私が、幽霊ごときに怯えるわけないでしょ！","ENG":"Ha! An aspiring hero of justice isn't scared of some ghost!","TWN":"哈！身為正義使者，你以為我會怕那種？"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"어림도 없지! 가브리엘! 승부다!","JPN":"負けないよ、ガブリエル！　勝負しよう！","ENG":"Oh, no, you don't! Gabriel! It's on!","TWN":"不可能！加布里埃爾！來一決勝負吧！"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"둘 다 꼴값 떨지 말고 조용히 좀 해줄래?","JPN":"2人ともふざけてないで静かにしてくれますか？","ENG":"Both of you, cut the act and keep it down.","TWN":"你們兩個都別鬧了，可以安靜點嗎？"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"파티마 씨의 말대로라면 CSE 레벨이 계속해서 상승 중일 거야.","JPN":"ファティマさんの言った通りであれば、CSEレベルは段々と上昇し続けているとのこと。","ENG":"If Fatima is right, the CSE level should still be rising.","TWN":"如果照法蒂瑪所說，CSE等級還在持續上升。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"아직은 3에서 천천히 상승하고 있지만, 조심해서 나쁠 건 없겠지.","JPN":"今はまだ3からゆっくり上昇していますが、用心しておいて損はないでしょう。","ENG":"It's creeping up from 3 for now, but there's no harm in being careful.","TWN":"雖然目前從3慢慢往上，但小心一點總是比較好。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"다량의 이터니움이 보관된 곳엔 무슨 일이 일어나도 이상하지 않을 테니까.","JPN":"大量のエタニウムが保管された場所では、何が起きてもおかしくありませんから。","ENG":"With that much Eternium stored here, anything could happen.","TWN":"畢竟在大量存放永恆之金的地方會發生什麼事都不奇怪。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"우리 정도면 3종 침식체 정도는 어떻게 해볼 만하지 않을까?","JPN":"第3種侵食体ぐらいなら、私たちでも何とかできるんじゃないかな？","ENG":"At our level, we can handle Category 3 C.O.s, right?","TWN":"以我們的程度，應該還能應付3級侵蝕體吧？"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"왜, 리더가 우리한테 지급해 준 얼터니움 리액터로 엄청 파워업 했잖아.","JPN":"ほら、リーダーにもらったオルタニウムリアクターで、すごくパワーアップしたじゃん。","ENG":"Leader gave us Alternium Reactors. We powered up a lot.","TWN":"畢竟老大給我們的黑化永恆之金電抗器讓我們變強不少。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"시간은 좀 걸리겠지만, 가능은 하겠지.","JPN":"そうですね。少々時間はかかるでしょうけど。","ENG":"It would take time, but doable.","TWN":"雖然要花點時間，但應該可行。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"리더가 있다면 얼마 걸리지도 않았겠지만, 지금은 그걸 따질 때가 아니니까.","JPN":"リーダーがいればすぐに終わるのでしょうが、今はそれをどうこう言っている場合じゃありませんから。","ENG":"If Leader were here, it would be faster, but that's not the point.","TWN":"如果老大在的話不會花太多時間，但現在不是考慮這些的時候。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"조심해서 움직이자.","JPN":"注意して移動しましょう。","ENG":"Move with caution.","TWN":"大家小心行動吧。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"곧 보관소 근처에 도착할 거야.","JPN":"もうすぐ保管所が見えてくるはずです。","ENG":"We are nearing the depot.","TWN":"很快就要到保管所附近了。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"역시…….","JPN":"やっぱり……","ENG":"As I thought...","TWN":"果然……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"저기가 보관소가 있는 곳이라고?","JPN":"あそこが保管所？","ENG":"That's where the depot is?","TWN":"那裡就是保管所？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"으… 이 주변의 침식체들이 전부 저기로 모인 것 같은데…….","JPN":"う……この辺りの侵食体は全部あそこに集まってるっぽいけど……","ENG":"Ugh... Looks like every C.O. nearby has gathered there...","TWN":"呃……附近所有侵蝕體好像都在那裡聚集了……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"저 고치는…….","JPN":"あの繭は……","ENG":"That cocoon...","TWN":"那個繭是……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"이터니움을 매개로 하여 부상한 녀석인가?","JPN":"エタニウムを媒介にして浮上したやつか？","ENG":"Did it ascend using Eternium as a catalyst?","TWN":"以永恆之金為媒介浮出的傢伙嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"가브리엘… 네가 그렇게 논리적인 추론을 할 줄은 몰랐어.","JPN":"ガブリエル……あなたにそんな論理的な推論ができるとは知らなかったよ。","ENG":"Gabriel... I didn't expect such logical deduction from you.","TWN":"加布里埃爾……沒想到你會做這麼有邏輯的推論。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"소녀여, 방금은 굉장히 무례한 말처럼 들렸다만?","JPN":"少女よ、今のは非常に失礼な発言に聞こえるのだが。","ENG":"Girl, that sounded rather rude.","TWN":"少女，妳這話聽起來很沒禮貌耶？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"가브리엘 말이 맞아.","JPN":"ガブリエルの言った通りです。","ENG":"Gabriel is right.","TWN":"加布里埃爾說得沒錯。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"최소 4종급 침식체의 고치일 확률이 높지.","JPN":"少なくとも、第4種級の繭である可能性が高いでしょう。","ENG":"Odds are high it's a cocoon for a Category 4 C.O.","TWN":"那高機率是4級侵蝕體的繭。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"복귀한다.","JPN":"復帰します。","ENG":"We're pulling back.","TWN":"撤退。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"뭐어?!","JPN":"ええ！？","ENG":"What?!","TWN":"什麼？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"잠깐, 이터니움 보관소가 바로 앞에 있다.","JPN":"待て、エタニウム保管所がすぐ目の前だぞ。","ENG":"Hold on. The Eternium depot is right there.","TWN":"等一下，永恆之金保管所就在眼前。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"우리의 목표는 이터니움을 회수해 돌아가는 것이 아닌가?","JPN":"私たちの目標はエタニウムを回収し帰還することではなかったのか？","ENG":"Our objective is to secure Eternium and return, no?","TWN":"我們的目標不是取回永恆之金後撤回嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그럼 저 고치는 누가 처리할 건데?","JPN":"では、あの繭は誰が処理するのですか？","ENG":"Then who's handling that cocoon?","TWN":"那個繭誰來處理？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"3종까지는 어떻게든 해볼 수 있겠지만, 4종부터는 넌센스야.","JPN":"第3種までならまだ何とかできますが、第4種以上となると話は別です。","ENG":"We might handle Category 3 somehow, but a Category 4 is nonsense.","TWN":"雖然我們還能嘗試與3級戰鬥，但我們不可能對付4級。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};